import { useState } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Card, Badge, Avatar, Input, Select, StatCard, Table, Tabs, ProgressBar, DonutChart, MiniBarChart, PageHeader, ProfileAlert, Modal } from "../../components/UI";
import { DashLayout } from "../../components/Layout";

// ─── ADMIN OVERVIEW ───────────────────────────────────────────────────────────
export const AdminOverview = () => (
  <div className="fade-up">
    <PageHeader title="Admin Dashboard" subtitle="Full system overview — Zenelait InfoTech Academy" />
    <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 24 }}>
      <StatCard icon="👨‍🎓" label="Total Students" value="12,048" change="↑ 240 this month" color={T.primaryL} />
      <StatCard icon="👨‍🏫" label="Teachers" value="85" change="↑ 3 new" color={T.accent} />
      <StatCard icon="👨‍👩‍👦" label="Parents" value="8,420" color={T.accentR} />
      <StatCard icon="💰" label="Revenue (Mar)" value="₹24.8L" change="↑ 12%" color={T.accentY} />
    </div>
    <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 24 }}>
      <StatCard icon="📚" label="Active Courses" value="64" color={T.accentG} />
      <StatCard icon="🏫" label="Active Batches" value="28" color={T.accent} />
      <StatCard icon="🎓" label="Certifications" value="5,240" color={T.accentY} />
      <StatCard icon="📩" label="New Queries" value="4" color={T.accentR} />
    </div>
    <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
      <Card>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15 }}>Revenue — Last 6 Months</div>
          <Btn size="xs" variant="dark">⬇ Export PDF</Btn>
        </div>
        <MiniBarChart data={[60, 75, 55, 80, 70, 95]} color={T.primary} />
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, color: T.muted, marginTop: 6 }}>
          {["Oct", "Nov", "Dec", "Jan", "Feb", "Mar ⭐"].map(m => <span key={m}>{m}</span>)}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12, marginTop: 18 }}>
          {[["Collected", "₹22.4L", T.accentG], ["Pending", "₹2.4L", T.accentY], ["Total", "₹24.8L", T.accent]].map(([l, v, c]) => (
            <div key={l} style={{ background: T.bg3, borderRadius: 10, padding: 12, textAlign: "center" }}>
              <div style={{ fontSize: 11, color: T.muted }}>{l}</div>
              <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 800, color: c }}>{v}</div>
            </div>
          ))}
        </div>
      </Card>
      <div>
        <Card style={{ marginBottom: 18 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Quick Actions</div>
          {[["👥 Manage Users", "users"], ["📚 Add Course", "courses"], ["📩 Contact Queries (4)", "queries"], ["📈 Revenue Report", "revenue"]].map(([l]) => (
            <div key={l} style={{ padding: "9px 12px", borderRadius: 8, cursor: "pointer", fontSize: 13, marginBottom: 6, background: T.bg3, border: `1px solid ${T.border}`, transition: "all .2s" }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = T.primary; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; }}
            >{l}</div>
          ))}
        </Card>
        <Card>
          <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>System Status</div>
          {[["Server", "● Online", T.accentG], ["Database", "● Healthy", T.accentG], ["Storage", "68%", T.accentY]].map(([l, v, c]) => (
            <div key={l} style={{ display: "flex", justifyContent: "space-between", fontSize: 13, padding: "8px 0", borderBottom: `1px solid rgba(45,33,96,.4)` }}>
              <span style={{ color: T.muted }}>{l}</span><span style={{ color: c, fontWeight: 700 }}>{v}</span>
            </div>
          ))}
          <ProgressBar value={68} color={T.accentY} height={6} />
        </Card>
      </div>
    </div>
  </div>
);

// ─── ADMIN PROFILE ────────────────────────────────────────────────────────────
export const AdminProfile = () => {
  const [pct] = useState(65);
  return (
    <div className="fade-up">
      <PageHeader title="Admin Profile" />
      <ProfileAlert pct={pct} onComplete={() => {}} />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 24 }}>
        <Card style={{ textAlign: "center", padding: 32 }}>
          <DonutChart pct={pct} color={T.primaryL} />
          <Avatar name="Z" size={80} color={T.accentY} />
